#include <bits/stdc++.h>
#define rep(i, n) for (int i = 0; i < n; i++)
#define PI pair<int, int>
#define all(v) v.begin(), v.end()
#define ll long long

constexpr int inf = 2000000000;

int turn_cnt = 0;

template <class T, class U>
inline bool chmin(T &a, U b) {
    if (a > b) {
        a = b;
        return true;
    }
    return false;
}
template <class T, class U>
inline bool chmax(T &a, U b) {
    if (a < b) {
        a = b;
        return true;
    }
    return false;
}
using namespace std;

struct UnionFind {
    int N;
    vector<int> par, siz;
    int find(int x) { return (par[x] == x ? x : par[x] = find(par[x])); }
    void merge(int x, int y) {
        x = find(x), y = find(y);
        if (x == y) return;
        if (siz[x] > siz[y]) swap(x, y);
        par[x] = y;
        siz[y] += siz[x];
    }
    UnionFind(int N) : N(N), siz(N, 1), par(N) {
        iota(par.begin(), par.end(), 0);
    }
};

// 方向を表す
int dx[] = {-1, 0, 1, 0}, dy[] = {0, 1, 0, -1};

// 操作
struct Act {
    int type, x, y;
};

struct Game {
    vector<vector<bool>> C;
    vector<vector<bool>> wall_hrz, wall_vert;
    vector<int> X, Y, wall_used, score;
    bool is_finished = false;

    int MAX_WALL = 10;
    int turn = 0;
    vector<Act> acts;

    // 連結性が保たれているかの判定
    bool isConnected() {
        UnionFind uf(81);
        rep(i, 9) rep(j, 9) {
            if (i < 8 && !wall_hrz[i][j]) uf.merge(i * 9 + j, (i + 1) * 9 + j);
            if (j < 8 && !wall_vert[i][j]) uf.merge(i * 9 + j, i * 9 + j + 1);
        }
        return uf.siz[uf.find(0)] == 81;
    }

    // 操作が適正であるかの判定
    bool isOK(Act act) {
        if (act.type == 0) {
            if (act.x == 0)  // 上
                return X[turn] && !wall_hrz[X[turn] - 1][Y[turn]];
            else if (act.x == 1)  // 右
                return Y[turn] != 8 && !wall_vert[X[turn]][Y[turn]];
            else if (act.x == 2)  // 下
                return X[turn] != 8 && !wall_hrz[X[turn]][Y[turn]];
            else if (act.x == 3)  // 左
                return Y[turn] && !wall_vert[X[turn]][Y[turn] - 1];
            else
                return false;
        } else if (act.type == 1) {
            if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if (wall_used[turn] == MAX_WALL)
                return false;  // 11 回目に置こうとしたらアウト
            if (wall_hrz[act.x][act.y] ||
                wall_hrz[act.x][act.y + 1])  // 既に置かれていたらアウト
                return false;
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            bool res = isConnected();  // 連結性チェック
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = false;
            return res;
        } else if (act.type == 2) {
            if (act.x < 0 || act.x > 7 || act.y < 0 || act.y > 7) return false;
            if (wall_used[turn] == MAX_WALL) return false;
            if (wall_vert[act.x][act.y] || wall_vert[act.x + 1][act.y])
                return false;
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            bool res = isConnected();
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = false;
            return res;
        } else
            return false;
    }

    // 操作の候補
    vector<Act> candidateActs() {
        vector<Act> res;
        rep(i, 4) {
            if (isOK(Act{0, i, 0}))
                res.push_back(Act{0, i, 0});  // 隣接マスへ移動
        }
        rep(i, 9) rep(j, 9) {
            if (isOK(Act{1, i, j}))
                res.push_back(Act{1, i, j});  // 水平方向の壁
            if (isOK(Act{2, i, j}))
                res.push_back(Act{2, i, j});  // 垂直方向の壁
        }
        return res;
    }

    // 操作を実行する
    bool applyAct(Act act, bool check = true) {
        if (check && !isOK(act)) return false;
        if (act.type == 0) {  // 隣接マスへ移動
            X[turn] += dx[act.x];
            Y[turn] += dy[act.x];
            if (C[X[turn]][Y[turn]]) {
                score[turn]++;
                C[X[turn]][Y[turn]] = false;
            }
        } else if (act.type == 1) {  // 水平方向の壁
            wall_hrz[act.x][act.y] = wall_hrz[act.x][act.y + 1] = true;
            wall_used[turn]++;
        } else {  // 垂直方向の壁
            wall_vert[act.x][act.y] = wall_vert[act.x + 1][act.y] = true;
            wall_used[turn]++;
        }
        // ゲームが終了しているかの判定
        bool flag = false;
        rep(i, 9) rep(j, 9) {
            if (C[i][j]) flag = true;
        }
        if (!flag) is_finished = true;
        acts.push_back(act);

        // 交代
        turn ^= 1;
        return true;
    }

    vector<vector<int> > apple_dist_search(int start_x, int start_y){
        queue<PI> que;
        vector<vector<int> > apple_dist(9,vector<int>(9,inf));
        apple_dist[start_x][start_y] = 0;
        que.push(PI(start_x, start_y));
        while(1){
            if(que.empty())break;
            int now_posx = que.front().first;
            int now_posy = que.front().second;
            que.pop();

            for(int i = 0;i < 4;i++){
                int next_posx = now_posx + dx[i];
                int next_posy = now_posy + dy[i];
                if (i == 0) {
                    // 上
                    if (!now_posx || wall_hrz[now_posx - 1][now_posy]) continue;
                } else if (i == 1) {
                    // 右
                    if (now_posy == 8 || wall_vert[now_posx][now_posy]) continue;
                } else if (i == 2) {
                    // 下
                    if (now_posx == 8 || wall_hrz[now_posx][now_posy]) continue;
                } else {
                    // 左
                    if (!now_posy || wall_vert[now_posx][now_posy - 1]) continue;
                }

                if(apple_dist[next_posx][next_posy] > apple_dist[now_posx][now_posy] + 1){
                    apple_dist[next_posx][next_posy] = apple_dist[now_posx][now_posy] + 1;
                    que.push(make_pair(next_posx, next_posy));
                }
            }
        }
        return apple_dist;
    }

    // 評価関数
    int eval(){
        constexpr int score_weight = 100; //現在持っているリンゴ一個あたりの評価値
        // constexpr int nearest_apple_weight = 5; //最も近いりんごからの距離に対する評価値
        constexpr int nearer_apple_weight = 15; //相手より近いりんごの個数に対する評価値
        constexpr int rest_wall_weight = 5; //残りの壁の数の差に対する評価値
        constexpr int apple_dist_sum_weight = 15; //距離の和に対する評価値

        int value = 0;

        value += (score[turn] - score[!turn]) * score_weight;

        int mydist_sum = 0;//全てのりんごに対する距離の総和 //->壁が置かれそうなところを評価してそれぞれのりんごに重みをつける

        //自分の位置,相手の位置からbfs
        vector<vector<int> > my_apple_dist = apple_dist_search(X[turn], Y[turn]);
        vector<vector<int> > enemy_apple_dist = apple_dist_search(X[!turn], Y[!turn]);

        // int my_nearest_apple_dist = inf;
        // int enemy_nearest_apple_dist = inf;
        int nearer_apple = 0;
        int my_apple_dist_sum = 0;
        int enemy_apple_dist_sum = 0;
        int cnt = 0;
        for(int i = 0;i < 9;i++){
            for(int j = 0;j < 9;j++){
                if (!C[i][j])continue;
                ++cnt;
                if((my_apple_dist[i][j] <= 1 && my_apple_dist[i][j] <= enemy_apple_dist[i][j]) || my_apple_dist[i][j] <= enemy_apple_dist[i][j] - 2)++nearer_apple;
                my_apple_dist_sum += my_apple_dist[i][j];
                enemy_apple_dist_sum += enemy_apple_dist[i][j];
                // my_nearest_apple_dist = min(my_nearest_apple_dist, my_apple_dist[i][j]);
                // enemy_nearest_apple_dist = min(enemy_nearest_apple_dist, enemy_apple_dist[i][j]);
            }
        }

        value += (double)(enemy_apple_dist_sum - my_apple_dist_sum) / cnt * apple_dist_sum_weight;

        value += nearer_apple * nearer_apple_weight;

        value += (wall_used[!turn] - wall_used[turn]) * rest_wall_weight;

        // value += (enemy_nearest_apple_dist - my_nearest_apple_dist) * nearest_apple_weight;


        return value + (int)rand() % 10 - 5;
    }

    // 一手何秒か
    static constexpr clock_t time_limit = 0.8 * CLOCKS_PER_SEC;

    // alpha beta探索を始めた時間
    clock_t start_time;

    // alpha beta探索
    pair<int, Act> alpha_beta_impl(int depth, int a, int b) {
        if (clock() - start_time >= time_limit) return {0, Act()};
        if (depth == 0) return {eval(), Act()};
        Act result_act;
        for (Act act: candidateActs()) if (isOK(act)) {
            if (act.type == 1 && turn_cnt <= 50) continue;
            auto nxt = *this;
            nxt.applyAct(act);
            int res = -nxt.alpha_beta_impl(depth - 1, -b, -a).first;
            if (clock() - start_time >= time_limit) return {0, Act()};
            if (a < res) {
                a = res;
                result_act = act;
            }
            if (a >= b) return {a, result_act};
        }
        return {a, result_act};
    }

    // alpha beta呼び出し
    Act alpha_beta() {
        start_time = clock();
        Act result_act;
        for (int depth = 1; ; ++depth) {
            auto [evaluation, act] = alpha_beta_impl(depth, -inf, inf);
            if (clock() - start_time >= time_limit) {
                return result_act;
            }
            result_act = act;
        }
    }

    // スコアや盤面を出力する（デバッグ用）
    void printBoard() {
        cerr << "Score: " << score[0] << " " << score[1] << "\n"
             << "Wall counter: " << wall_used[0] << " " << wall_used[1] << endl
             << endl;
        rep(i, 9) {
            rep(j, 9) {
                if (i == X[0] && j == Y[0] && i == X[1] && j == Y[1])
                    cerr << " AB";
                else if (i == X[0] && j == Y[0])
                    cerr << " A ";
                else if (i == X[1] && j == Y[1])
                    cerr << " B ";
                else {
                    if (C[i][j])
                        cerr << " # ";
                    else
                        cerr << " . ";
                }
                if (j < 8) cerr << (wall_vert[i][j] ? " | " : "   ");
            }
            cerr << endl;
            if (i != 8) {
                rep(j, 9) {
                    if (j) cerr << "   ";
                    cerr << (wall_hrz[i][j] ? "---" : "   ");
                }
            }
            cerr << endl;
        }
        cerr << endl;
    }
    Game()
        : C(9, vector<bool>(9)),
          wall_hrz(9, vector<bool>(9)),
          wall_vert(9, vector<bool>(9)),
          X(2),
          Y(2),
          wall_used(2),
          score(2) {
        wall_used[0] = wall_used[1] = 0;
        score[0] = score[1] = 0;
        X[0] = 8, X[1] = 0, Y[0] = Y[1] = 4;
    }
};

// 処理に掛かっている合計時間
double tim_sum;

// 自分のターンになったら呼ばれるので、操作を選ぶ。先手なら game.turn=0,
// 後手なら game.turn=1 の状態で呼ばれる
Act choose(Game game) {
    // 時間計測用
    chrono::system_clock::time_point clk = chrono::system_clock::now();

    vector<Act> acts = game.candidateActs();
    int mx = -1e9;
    Act best_act;
    for (Act act : acts) {
        Game new_game = game;
        new_game.applyAct(act);
        if (chmax(mx, new_game.score[game.turn] - new_game.score[!game.turn])) {
            best_act = act;
        }
    }

    // 時間計測用
    tim_sum += static_cast<double>(chrono::duration_cast<chrono::microseconds>(
                                       chrono::system_clock::now() - clk)
                                       .count() /
                                   1000000.0);
    return best_act;
}
int main() {
    srand((unsigned)time(nullptr));
    string s;
    cin >> s;
    Game game;
    rep(i, 9) {
        rep(j, 9) {
            char c;
            cin >> c;
            if (c == '#')
                game.C[i][j] = true;
            else
                game.C[i][j] = false;
        }
    }
    int turn = 0, myturn = (s == "First" ? 0 : 1);
    while (1) {
        if (turn == myturn) {
            Act act = game.alpha_beta();
            game.applyAct(act);
            if (!act.type) {
                cout << act.type << " " << act.x << endl;
            } else {
                cout << act.type << " " << act.x << " " << act.y << endl;
            }
        } else {
            int t;
            cin >> t;
            if (!t) {
                int x;
                cin >> x;
                game.applyAct(Act{0, x, 0});
            } else if (t <= 2) {
                int x, y;
                cin >> x >> y;
                game.applyAct(Act{t, x, y});
            } else {
                return 0;
            }
        }
        // デバッグ用
        // game.printBoard();
        turn ^= 1;
        ++turn_cnt;
    }
}
